import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def read_sql(name):
    return (ROOT / "sql" / name).read_text(encoding="ascii")


def make_db():
    db = sqlite3.connect(":memory:")
    db.executescript(
        """
        CREATE TABLE export_profile (
            profile_name TEXT PRIMARY KEY,
            field_separator TEXT NOT NULL CHECK (length(field_separator) = 1),
            record_separator TEXT NOT NULL CHECK (record_separator IN ('LF', 'CRLF'))
        );

        CREATE TABLE customer (
            customer_id INTEGER PRIMARY KEY,
            display_name TEXT
        );

        CREATE TABLE fulfillment_order (
            order_id INTEGER PRIMARY KEY,
            delivery_note TEXT
        );
        """
    )
    db.execute("INSERT INTO export_profile VALUES ('default', ',', 'LF')")
    db.execute("INSERT INTO customer VALUES (7, 'North Annex')")
    db.execute("INSERT INTO fulfillment_order VALUES (41, 'Leave at desk')")
    return db


def test_renders_a_customer_with_the_default_profile():
    db = make_db()
    rendered = db.execute(
        read_sql("render_customer_row.sql"),
        {"profile_name": "default", "customer_id": 7},
    ).fetchone()[0]

    assert rendered == "7,North Annex\n"


def test_renders_an_order_with_the_default_profile():
    db = make_db()
    rendered = db.execute(
        read_sql("render_order_row.sql"),
        {"profile_name": "default", "order_id": 41},
    ).fetchone()[0]

    assert rendered == "41,Leave at desk\n"
